   282	fn format_doc_comments(comments: &str, js_doc_comments: Option<String>) -> String {
   283	    let body: String = comments.lines().fold(String::new(), |mut output, c| {
   284	        output.push_str(" *");
   285	        if !c.is_empty() && !c.starts_with(' ') {
   286	            output.push(' ');
   287	        }
   288	        output.push_str(c);
   289	        output.push('\n');
   290	        output
   291	    });
   292	    let doc = if let Some(docs) = js_doc_comments {
   293	        docs.lines().fold(String::new(), |mut output: String, l| {
   294	            let _ = writeln!(output, " * {l}");
   295	            output
   296	        })
   297	    } else {
   298	        String::new()
   299	    };
   300	    if body.is_empty() && doc.is_empty() {
   301	        // don't emit empty doc comments
   302	        String::new()
   303	    } else {
   304	        format!("/**\n{body}{doc} */\n")
   305	    }
   306	}
