   308	/// Defines an export with an optional namespace path segment
   309	/// Namespaces are defined into the exports map as needed via ExportEntry::Namespace
   310	fn define_export(
   311	    exports: &mut BTreeMap<String, ExportEntry>,
   312	    export_name: &str,
   313	    ns_path: &[String],
   314	    export: ExportEntry,
   315	) -> Result<(), Error> {
   316	    // Namespaces are only defined into exports by this function, not by consumers of this function.
   317	    assert!(!matches!(export, ExportEntry::Namespace(_)));
   318	
   319	    if ns_path.is_empty() {
   320	        match exports.entry(export_name.to_string()) {
   321	            Entry::Vacant(e) => {
   322	                e.insert(export);
   323	            }
   324	            Entry::Occupied(mut e) => {
   325	                if let ExportEntry::Definition(def) = export {
   326	                    if def.definition.is_empty() {
   327	                        if let ExportEntry::Namespace(ns) = e.get_mut() {
   328	                            if ns.id.is_none() {
   329	                                ns.id = Some(def.identifier);
   330	                                return Ok(());
   331	                            }
   332	                        }
   333	                    }
   334	                }
   335	                bail!("Cannot define export over existing namespace {export_name}");
   336	            }
   337	        };
   338	    } else {
   339	        let export_entry = exports
   340	            .entry(ns_path[0].to_string())
   341	            .or_insert(ExportEntry::Namespace(Default::default()));
   342	        let ns = match export_entry {
   343	            ExportEntry::Namespace(ns) => ns,
   344	            ExportEntry::Definition(def) if def.definition.is_empty() => {
   345	                *export_entry = ExportEntry::Namespace(ExportedNamespace {
   346	                    id: Some(def.identifier.to_string()),
   347	                    ns: BTreeMap::new(),
   348	                });
   349	                let ExportEntry::Namespace(ns) = export_entry else {
   350	                    unreachable!();
   351	                };
   352	                ns
   353	            }
   354	            _ => {
   355	                bail!("Cannot to define namespace export over existing definition {export_name}");
   356	            }
   357	        };
   358	        define_export(&mut ns.ns, export_name, &ns_path[1..], export)?;
   359	    }
   360	    Ok(())
   361	}
