   363	/// Returns a string to tack on to the end of an expression to access a
   364	/// property named `name` of the object that expression resolves to.
   365	///
   366	/// In most cases, this is `.<name>`, generating accesses like `foo.bar`.
   367	/// However, if `name` is not a valid JavaScript identifier, it becomes
   368	/// `["<name>"]` instead, creating accesses like `foo["kebab-case"]`.
   369	fn property_accessor(name: &str) -> String {
   370	    if is_valid_ident(name) {
   371	        format!(".{name}")
   372	    } else {
   373	        format!("[\"{}\"]", name.escape_default())
   374	    }
   375	}
